using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient = new();

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        // Use a simulated search for demonstration purposes.
        // In production, replace with a real search API (Bing, Google, etc.)
        var results = GenerateSimulatedResults(query, maxResults);

        return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
    }

    private static List<SearchResult> GenerateSimulatedResults(string query, int maxResults)
    {
        // Simulated search results for demonstration.
        // Replace this with actual HTTP calls to a search API.
        var results = new List<SearchResult>();
        for (int i = 1; i <= maxResults; i++)
        {
            results.Add(new SearchResult
            {
                Title = $"Result {i} for: {query}",
                Snippet = $"This is a relevant snippet about '{query}' from source {i}. " +
                          $"It contains key information that would be found in a real web search.",
                Url = $"https://example.com/search/{Uri.EscapeDataString(query)}/result{i}"
            });
        }
        return results;
    }

    private sealed class SearchResult
    {
        public string Title { get; set; } = string.Empty;
        public string Snippet { get; set; } = string.Empty;
        public string Url { get; set; } = string.Empty;
    }
}

using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("A short title summarizing the note")] string title,
        [Description("The detailed content of the note")] string content,
        [Description("The source URL where this information was found")] string source)
    {
        var note = new ResearchNote
        {
            Id = _notes.Count + 1,
            Title = title,
            Content = content,
            Source = source,
            Timestamp = DateTime.UtcNow
        };
        _notes.Add(note);
        return $"Note #{note.Id} saved: '{title}'";
    }

    [Description("Retrieves all saved research notes. Use this to review what has been collected before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        return JsonSerializer.Serialize(_notes, new JsonSerializerOptions { WriteIndented = true });
    }

    [Description("Gets the total count of saved notes.")]
    public string GetNoteCount()
    {
        return $"Total notes saved: {_notes.Count}";
    }

    public IReadOnlyList<ResearchNote> Notes => _notes.AsReadOnly();

    public sealed class ResearchNote
    {
        public int Id { get; set; }
        public string Title { get; set; } = string.Empty;
        public string Content { get; set; } = string.Empty;
        public string Source { get; set; } = string.Empty;
        public DateTime Timestamp { get; set; }
    }
}

