using System.ComponentModel;
using System.Text.Json;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("A short title summarizing the note")] string title,
        [Description("The detailed content of the note")] string content,
        [Description("The source URL where this information was found")] string source)
    {
        var note = new ResearchNote
        {
            Id = _notes.Count + 1,
            Title = title,
            Content = content,
            Source = source,
            Timestamp = DateTime.UtcNow
        };
        _notes.Add(note);
        return $"Note #{note.Id} saved: '{title}'";
    }

    [Description("Retrieves all saved research notes. Use this to review collected findings before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return JsonSerializer.Serialize(_notes, new JsonSerializerOptions { WriteIndented = true });
    }

    [Description("Gets the total count of saved notes.")]
    public string GetNoteCount()
    {
        return $"Total notes saved: {_notes.Count}";
    }

    public IReadOnlyList<ResearchNote> Notes => _notes.AsReadOnly();

    public sealed class ResearchNote
    {
        public int Id { get; set; }
        public string Title { get; set; } = string.Empty;
        public string Content { get; set; } = string.Empty;
        public string Source { get; set; } = string.Empty;
        public DateTime Timestamp { get; set; }
    }
}

