using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Configuration;
using Microsoft.Agents.AI.ChatCompletion;
using ResearchAgent.Tools;

var configuration = new ConfigurationBuilder()
    .AddEnvironmentVariables()
    .Build();

var apiKey = configuration["OPENAI_API_KEY"]
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = configuration["OPENAI_MODEL"] ?? "gpt-4o-mini-2024-07-18";

// Set up tools
var webSearchTool = new WebSearchTool();
var noteTakingTool = new NoteTakingTool();

var tools = new AIFunctionFactory[]
{
}.ToList<object>();

// Create the chat client with tools via MEAI
var chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
    Tools =
    [
        AIFunctionFactory.Create(webSearchTool.SearchWebAsync),
        AIFunctionFactory.Create(noteTakingTool.SaveNote),
        AIFunctionFactory.Create(noteTakingTool.GetAllNotes),
        AIFunctionFactory.Create(noteTakingTool.GetNoteCount),
    ]
};

// Configure the agent
var agentOptions = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

var agent = new ChatClientAgent(chatClient, agentOptions)
{
    Name = "ResearchAgent",
    Description = "An AI agent that researches topics by searching the web and taking notes, then summarizes findings.",
    Instructions = """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using multiple queries to cover different aspects.
        2. Save important findings as notes using the note-taking tool, including the source URL.
        3. After gathering enough information (at least 3 notes), retrieve all notes and write a comprehensive summary.
        4. Present the final summary with key findings and source citations.
        Be thorough but concise. Focus on factual information.
        """
};

// Get the research topic
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a topic to research: ");
    topic = Console.ReadLine() ?? "artificial intelligence";
}

Console.WriteLine($"\nResearching: {topic}\n");
Console.WriteLine(new string('─', 50));

// Run the agent
var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}")
};

await foreach (var message in agent.InvokeStreamingAsync(history, chatOptions))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"\nResearch complete. {noteTakingTool.Notes.Count} notes collected.");

